import random, itertools, math, numpy as np
def count_good(x):
    b=len(x)
    thr=2/b
    return sum(1 for i in range(b) for j in range(i+1,b) if x[i]+x[j] >= thr-1e-12)
mins={}
argmins={}
for b in range(6,11):
    best=10**9
    bestx=None
    for _ in range(200000):
        # random dirichlet with varied alpha
        alpha=10**random.uniform(-2,2)
        y=np.random.gamma(alpha,1,b)
        x=y/y.sum()
        c=count_good(x)
        if c<best:
            best=c; bestx=x.copy()
            if best < b-1: break
    mins[b]=best; argmins[b]=bestx
mins, {b:argmins[b] for b in mins}
